// test/integration/full_system_crud_test.dart

import 'dart:convert';
import 'package:flutter_test/flutter_test.dart';
import 'package:http/http.dart' as http;
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/data/utils/security_matrix.dart';
import '../services/test_helper.dart';

/// Configuração para testar uma tela específica
class ScreenTestConfig {
  final String endpoint;
  final Map<String, dynamic> createPayload;
  final Map<String, dynamic> updatePayload;
  final String idField; // Campo que identifica o ID no retorno (ex: 'id')

  ScreenTestConfig({
    required this.endpoint,
    required this.createPayload,
    required this.updatePayload,
    this.idField = 'id',
  });
}

void main() {
  group('Fluxo Real do Sistema (CRUD por Tela)', () {
    late String token;
    late Map<String, String> headers;

    // 1. Setup: Realiza o login uma única vez antes dos testes
    setUpAll(() async {
      token = await loginAndGetToken();
      headers = authHeaders(token);
      print('🔑 Token obtido com sucesso para testes de integração.');
    });

    // 2. Definição dos Dados de Teste
    // Aqui mapeamos a AppScreen -> Endpoint e Dados Fakes
    final Map<AppScreen, ScreenTestConfig> screenConfigs = {
      // Exemplo: Teste da tela de Parceiros (ou Empresas)
      // Ajuste 'ApiLinks.empresas' para o link real da sua API
      AppScreen.parceiros: ScreenTestConfig(
        endpoint:
            '${ApiLinks.baseUrl}/parceiros', // Ajuste conforme seu ApiLinks
        createPayload: {
          "nome": "Empresa Teste Automatizado",
          "razaoSocial": "Razão Social Teste",
          "email": "teste@auto.com",
          "telefone": "11999999999",
          "cnpj": "00000000000100", // CNPJ válido fictício se necessário
          "ativo": true
        },
        updatePayload: {
          "nome": "Empresa Teste UPDATE",
          "razaoSocial": "Razão Social UPDATE",
        },
      ),

      // Exemplo: Contas a Pagar
      AppScreen.contasPagar: ScreenTestConfig(
        endpoint: '${ApiLinks.baseUrl}/financeiro/pagar',
        createPayload: {
          "descricao": "Conta de Luz Teste",
          "valor": 150.50,
          "dataVencimento": DateTime.now().toIso8601String(),
          "status": "ABERTO"
        },
        updatePayload: {
          "valor": 200.00,
        },
      ),

      // Adicione outras telas aqui conforme necessário...
    };

    // 3. Execução Dinâmica dos Testes
    // Itera sobre as configurações e cria um grupo de testes para cada tela
    screenConfigs.forEach((screen, config) {
      group('Tela: ${screen.name}', () {
        int? createdId;

        test('1. FETCH (GET) - Deve listar dados da tela', () async {
          final response = await http.get(
            Uri.parse(config.endpoint),
            headers: headers,
          );

          expectListOk(response.statusCode, 'GET ${screen.name}');

          // Valida se retornou um JSON válido
          final body = jsonDecode(response.body);
          expect(body, isNotNull);
        });

        test('2. INSERT (POST) - Deve criar um novo registro', () async {
          // Injeta dados de auditoria (empresa, usuario) automaticamente
          final payload = withAudit(config.createPayload);

          final response = await http.post(
            Uri.parse(config.endpoint),
            headers: headers,
            body: jsonEncode(payload),
          );

          expectInsertOk(response.statusCode, 'POST ${screen.name}');

          final body = jsonDecode(response.body);

          // Tenta extrair o ID criado.
          // A estrutura depende do seu backend (ex: body['id'] ou body['data']['id'])
          createdId = body[config.idField] ??
              body['data']?[config.idField] ??
              body['dados']?[config.idField];

          expect(createdId, isNotNull, reason: 'ID não retornado após criação');
          print('   ✅ Criado ID: $createdId em ${screen.name}');
        });

        test('3. UPDATE (PUT) - Deve atualizar o registro criado', () async {
          if (createdId == null) {
            markTestSkipped('Pulo UPDATE pois o INSERT falhou (ID null).');
            return;
          }

          // Mescla o payload de update com o ID e auditoria
          final payload = withAudit({
            ...config.updatePayload,
            config.idField: createdId,
          });

          // Assume que o PUT é na URL base (com ID no body) ou URL/id
          // Ajuste conforme seu padrão REST. Muitos usam: url/id
          final url = Uri.parse('${config.endpoint}/$createdId');
          // OU se seu backend espera PUT na raiz com ID no body:
          // final url = Uri.parse(config.endpoint);

          final response = await http.put(
            url,
            headers: headers,
            body: jsonEncode(payload),
          );

          expectUpdateOk(response.statusCode, 'PUT ${screen.name}');
        });

        test('4. DELETE - Deve remover o registro criado', () async {
          if (createdId == null) {
            markTestSkipped('Pulo DELETE pois o INSERT falhou (ID null).');
            return;
          }

          final url = Uri.parse('${config.endpoint}/$createdId');

          final response = await http.delete(
            url,
            headers: headers,
          );

          expectDeleteOk(response.statusCode, 'DELETE ${screen.name}');
        });
      });
    });
  });
